"use client";

import { useEffect, useState } from "react";
import { Requisition } from "@/types";
import { getRequisitions, updateRequisitionStatus } from "@/lib/requisitions";
import { useAuth } from "@/context/AuthContext";

export default function ApprovalsPage() {
    const { user } = useAuth();
    const [requisitions, setRequisitions] = useState<Requisition[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchReqs = async () => {
        setLoading(true);
        const data = await getRequisitions();
        // Filter for only PENDING requests
        const pending = data.filter(r => r.status === 'PENDING').sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
        setRequisitions(pending);
        setLoading(false);
    };

    useEffect(() => {
        fetchReqs();
    }, []);

    const handleAction = async (id: string, action: 'APPROVED' | 'REJECTED') => {
        if (!confirm(`Are you sure you want to ${action} this request?`)) return;
        if (!id) return;

        try {
            await updateRequisitionStatus(id, action, user?.uid);

            if (action === 'APPROVED' && user?.uid) {
                // Auto-generate PO - needs full requisition object, which we have in state
                const req = requisitions.find(r => r.id === id);
                if (req) {
                    await createPOFromRequisition(req, user.uid);
                    alert("Request Approved & PO Generated!");
                }
            } else {
                await fetchReqs(); // Refresh list only if not redirecting or other logic
            }
            await fetchReqs(); // Refresh list
        } catch (error) {
            console.error(error);
            alert("Error updating status");
        }
    };

    if (loading) return <div>Loading approvals...</div>;

    return (
        <div>
            <h1 style={{ fontSize: '1.875rem', fontWeight: 'bold', marginBottom: '2rem', color: 'var(--primary)' }}>Pending Approvals</h1>

            {requisitions.length === 0 ? (
                <div className="card" style={{ textAlign: 'center', padding: '3rem' }}>
                    <p style={{ color: 'var(--text-secondary)' }}>No pending requests require your approval.</p>
                </div>
            ) : (
                <div style={{ display: 'grid', gap: '1.5rem' }}>
                    {requisitions.map((req) => (
                        <div key={req.id} className="card" style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', borderBottom: '1px solid var(--border)', paddingBottom: '1rem' }}>
                                <div>
                                    <div style={{ fontWeight: 'bold', fontSize: '1.1rem' }}>#{req.id?.slice(-6).toUpperCase()} — {req.vendorName}</div>
                                    <div style={{ fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
                                        Requested by <strong>{req.requesterName}</strong> ({req.department}) on {req.createdAt.toLocaleDateString()}
                                    </div>
                                </div>
                                <div style={{ fontSize: '1.25rem', fontWeight: 'bold', color: 'var(--primary)' }}>
                                    ${req.totalAmount.toFixed(2)}
                                </div>
                            </div>

                            <div>
                                <table style={{ width: '100%', fontSize: '0.9rem' }}>
                                    <tbody>
                                        {req.items.map((item, idx) => (
                                            <tr key={idx}>
                                                <td style={{ padding: '0.25rem 0' }}>{item.quantity}x {item.description}</td>
                                                <td style={{ textAlign: 'right', padding: '0.25rem 0' }}>${item.total.toFixed(2)}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>

                            <div style={{ backgroundColor: '#f8fafc', padding: '0.75rem', borderRadius: 'var(--radius-sm)', fontSize: '0.875rem', fontStyle: 'italic', border: '1px solid var(--border)' }}>
                                " {req.justification} "
                            </div>

                            <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end', marginTop: '0.5rem' }}>
                                <button
                                    onClick={() => req.id && handleAction(req.id, 'REJECTED')}
                                    className="btn"
                                    style={{ border: '1px solid var(--error)', color: 'var(--error)' }}
                                >
                                    Reject
                                </button>
                                <button
                                    onClick={() => req.id && handleAction(req.id, 'APPROVED')}
                                    className="btn btn-primary"
                                    style={{ backgroundColor: 'var(--success)' }}
                                >
                                    Approve Request
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
}
